change_4_js_helper_and_hashchange.insert_after_showTab:
function goToDefinition(defId) {
  const el = document.getElementById(defId);
  if (!el) return;
  const parentTab = el.closest('.tab-content');
  if (parentTab && !parentTab.classList.contains('active')) {
    showTab(parentTab.id, { skipHash: true, skipScroll: true });
  }
  history.pushState({ tab: parentTab ? parentTab.id : null, anchor: defId }, '', '#' + defId);
  setTimeout(function() {
    el.scrollIntoView({ behavior: 'smooth', block: 'center' });
    el.classList.add('verdict-def-flash');
    setTimeout(function() { el.classList.remove('verdict-def-flash'); }, 1600);
  }, 30);
}

change_4_js_helper_and_hashchange.insert_after_load_handler:
window.addEventListener('hashchange', function() {
  const hash = window.location.hash.slice(1);
  if (!hash || hash.indexOf('def-') !== 0) return;
  const el = document.getElementById(hash);
  if (!el) return;
  const parentTab = el.closest('.tab-content');
  if (parentTab && !parentTab.classList.contains('active')) {
    showTab(parentTab.id, { skipHash: true, skipScroll: true });
  }
  setTimeout(function() {
    el.scrollIntoView({ behavior: 'smooth', block: 'center' });
    el.classList.add('verdict-def-flash');
    setTimeout(function() { el.classList.remove('verdict-def-flash'); }, 1600);
  }, 30);
});

